export interface Geo {
  city?: string
  country?: string
  countryCode?: string
  region?: string
  latitude?: string
  longitude?: string
  timezone?: string
}

export const COUNTRY_NAMES: ReadonlyMap<string, string> = new Map([
  ['US', 'United States'],
  ['GB', 'United Kingdom'],
  ['DE', 'Germany'],
  ['FR', 'France'],
  ['JP', 'Japan'],
  ['CN', 'China'],
  ['IN', 'India'],
  ['BR', 'Brazil'],
  ['AU', 'Australia'],
  ['CA', 'Canada'],
])

function toRad(deg: number): number {
  return (deg * Math.PI) / 180
}

export function geoFromHeaders(headers: Headers): Geo {
  const result: Geo = {}

  const rawCity = headers.get('x-vercel-ip-city')
  if (rawCity) {
    try {
      result.city = decodeURIComponent(rawCity)
    } catch {
      result.city = rawCity
    }
  }

  const countryCode =
    headers.get('x-vercel-ip-country') || headers.get('cf-ipcountry')
  if (countryCode) {
    result.countryCode = countryCode
    const countryName = COUNTRY_NAMES.get(countryCode.toUpperCase())
    if (countryName) {
      result.country = countryName
    }
  }

  const region = headers.get('x-vercel-ip-country-region')
  if (region) {
    result.region = region
  }

  const latitude = headers.get('x-vercel-ip-latitude')
  if (latitude) {
    result.latitude = latitude
  }

  const longitude = headers.get('x-vercel-ip-longitude')
  if (longitude) {
    result.longitude = longitude
  }

  const timezone = headers.get('x-vercel-ip-timezone')
  if (timezone) {
    result.timezone = timezone
  }

  return result
}

export function geo({ headers }: { headers: Headers }): Geo {
  return geoFromHeaders(headers)
}

export function isInRegion(geoData: Geo, regions: string[]): boolean {
  if (!geoData.countryCode) return false
  const code = geoData.countryCode.toUpperCase()
  return regions.some((r) => r.toUpperCase() === code)
}

export function geoDistance(
  lat1: string,
  lon1: string,
  lat2: string,
  lon2: string
): number {
  const R = 6371 // Earth's radius in kilometers
  const lat1Num = parseFloat(lat1)
  const lon1Num = parseFloat(lon1)
  const lat2Num = parseFloat(lat2)
  const lon2Num = parseFloat(lon2)

  const dLat = toRad(lat2Num - lat1Num)
  const dLon = toRad(lon2Num - lon1Num)
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(toRad(lat1Num)) *
      Math.cos(toRad(lat2Num)) *
      Math.sin(dLon / 2) *
      Math.sin(dLon / 2)
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))
  return R * c
}

