import {
  geo,
  geoFromHeaders,
  isInRegion,
  geoDistance,
  COUNTRY_NAMES,
} from './geo'

describe('geoFromHeaders', () => {
  it('should extract all geo fields from Vercel headers', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'London',
      'x-vercel-ip-country': 'GB',
      'x-vercel-ip-country-region': 'ENG',
      'x-vercel-ip-latitude': '51.5074',
      'x-vercel-ip-longitude': '-0.1278',
      'x-vercel-ip-timezone': 'Europe/London',
    })
    const result = geoFromHeaders(headers)
    expect(result.city).toBe('London')
    expect(result.countryCode).toBe('GB')
    expect(result.country).toBe('United Kingdom')
    expect(result.region).toBe('ENG')
    expect(result.latitude).toBe('51.5074')
    expect(result.longitude).toBe('-0.1278')
    expect(result.timezone).toBe('Europe/London')
  })

  it('should return undefined fields when no headers are present', () => {
    const headers = new Headers()
    const result = geoFromHeaders(headers)
    expect(result.city).toBeUndefined()
    expect(result.country).toBeUndefined()
    expect(result.countryCode).toBeUndefined()
    expect(result.region).toBeUndefined()
    expect(result.latitude).toBeUndefined()
    expect(result.longitude).toBeUndefined()
    expect(result.timezone).toBeUndefined()
  })

  it('should handle partial headers', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'US',
      'x-vercel-ip-latitude': '40.7128',
    })
    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('US')
    expect(result.country).toBe('United States')
    expect(result.latitude).toBe('40.7128')
    expect(result.city).toBeUndefined()
    expect(result.region).toBeUndefined()
    expect(result.longitude).toBeUndefined()
    expect(result.timezone).toBeUndefined()
  })

  it('should URL-decode the city name', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'S%C3%A3o%20Paulo',
    })
    const result = geoFromHeaders(headers)
    expect(result.city).toBe('S\u00e3o Paulo')
  })

  it('should handle malformed percent-encoding gracefully', () => {
    const headers = new Headers({
      'x-vercel-ip-city': '%ZZbadvalue',
    })
    const result = geoFromHeaders(headers)
    expect(result.city).toBe('%ZZbadvalue')
  })

  it('should fall back to cf-ipcountry when x-vercel-ip-country is absent', () => {
    const headers = new Headers({
      'cf-ipcountry': 'DE',
    })
    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('DE')
    expect(result.country).toBe('Germany')
  })

  it('should prefer x-vercel-ip-country over cf-ipcountry', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'FR',
      'cf-ipcountry': 'DE',
    })
    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('FR')
    expect(result.country).toBe('France')
  })

  it('should leave country undefined when countryCode is not in COUNTRY_NAMES', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'XX',
    })
    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('XX')
    expect(result.country).toBeUndefined()
  })
})

describe('geo', () => {
  it('should accept { headers } object and return Geo data', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'Tokyo',
      'x-vercel-ip-country': 'JP',
      'x-vercel-ip-latitude': '35.6762',
      'x-vercel-ip-longitude': '139.6503',
      'x-vercel-ip-timezone': 'Asia/Tokyo',
    })
    const result = geo({ headers })
    expect(result.city).toBe('Tokyo')
    expect(result.countryCode).toBe('JP')
    expect(result.country).toBe('Japan')
    expect(result.latitude).toBe('35.6762')
    expect(result.longitude).toBe('139.6503')
    expect(result.timezone).toBe('Asia/Tokyo')
  })

  it('should produce identical results to geoFromHeaders', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'Berlin',
      'x-vercel-ip-country': 'DE',
      'x-vercel-ip-country-region': 'BE',
      'x-vercel-ip-latitude': '52.5200',
      'x-vercel-ip-longitude': '13.4050',
      'x-vercel-ip-timezone': 'Europe/Berlin',
    })
    const fromGeo = geo({ headers })
    const fromHeaders = geoFromHeaders(headers)
    expect(fromGeo).toEqual(fromHeaders)
  })
})

describe('isInRegion', () => {
  it('should return true when countryCode matches a region', () => {
    expect(isInRegion({ countryCode: 'US' }, ['US', 'CA', 'MX'])).toBe(true)
  })

  it('should perform case-insensitive comparison', () => {
    expect(isInRegion({ countryCode: 'us' }, ['US', 'CA'])).toBe(true)
    expect(isInRegion({ countryCode: 'US' }, ['us', 'ca'])).toBe(true)
  })

  it('should return false when countryCode does not match', () => {
    expect(isInRegion({ countryCode: 'GB' }, ['US', 'CA', 'MX'])).toBe(false)
  })

  it('should return false when countryCode is undefined', () => {
    expect(isInRegion({}, ['US', 'CA'])).toBe(false)
  })

  it('should return false for empty regions array', () => {
    expect(isInRegion({ countryCode: 'US' }, [])).toBe(false)
  })
})

describe('geoDistance', () => {
  it('should return 0 for identical points', () => {
    const distance = geoDistance('40.7128', '-74.0060', '40.7128', '-74.0060')
    expect(distance).toBe(0)
  })

  it('should calculate distance between New York and London (~5570 km)', () => {
    // NYC: 40.7128, -74.0060 | London: 51.5074, -0.1278
    const distance = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
    expect(distance).toBeGreaterThan(5520)
    expect(distance).toBeLessThan(5620)
  })

  it('should be symmetric (distance A->B equals B->A)', () => {
    const ab = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
    const ba = geoDistance('51.5074', '-0.1278', '40.7128', '-74.0060')
    expect(ab).toBe(ba)
  })
})

describe('COUNTRY_NAMES', () => {
  it('should contain at least 10 entries', () => {
    expect(COUNTRY_NAMES.size).toBeGreaterThanOrEqual(10)
  })

  it('should map US to United States', () => {
    expect(COUNTRY_NAMES.get('US')).toBe('United States')
  })

  it('should map GB to United Kingdom', () => {
    expect(COUNTRY_NAMES.get('GB')).toBe('United Kingdom')
  })
})

